import{_ as a,c as e,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/claude-skills-AI工具.md","filePath":"github汇总/AI工具/claude-skills-AI工具.md"}'),d={name:"github汇总/AI工具/claude-skills-AI工具.md"};function h(o,l,n,t,s,c){return i(),e("div",null,l[0]||(l[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>claude-skills</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>alirezarezvani</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><ul><li>使用Claude需要手动编写大量提示词</li><li>缺少专业领域的标准化技能模板</li><li>不同岗位的工作难以标准化和自动化</li><li>无法快速为Claude添加专业能力</li></ul><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>适用于Claude Code和Claude AI的专业技能集合</li><li>包含多类岗位的Agent技能</li><li>HR板块包含18个技能，支持KPI设计、绩效评估、晋升建议</li><li>可直接在Claude Code中安装使用</li><li>提供标准化的专业工作流程</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>专业的岗位技能集合</li><li>HR功能特别强大，包含18个技能</li><li>GitHub星标已超两千</li><li>可直接在Claude Code中安装使用</li><li>提升Claude的专业工作能力</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明，但GitHub星标已超两千，在开源社区有一定影响力</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/alirezarezvani/claude-skills" target="_blank" rel="noreferrer">https://github.com/alirezarezvani/claude-skills</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>本教程适用于想要使用claude-skills提升Claude Code或Claude AI能力的用户。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><h3 id="_1-claude-code检查" tabindex="-1">1. Claude Code检查 <a class="header-anchor" href="#_1-claude-code检查" aria-label="Permalink to “1. Claude Code检查”">​</a></h3><ul><li>步骤目标：确认已安装Claude Code</li><li>执行位置：本机</li><li>检查方法：确认Claude Code已正确安装并可正常使用</li><li>成功标志：Claude Code可正常启动和使用</li><li>失败处理：请先安装Claude Code</li></ul><h3 id="_2-网络访问检查" tabindex="-1">2. 网络访问检查 <a class="header-anchor" href="#_2-网络访问检查" aria-label="Permalink to “2. 网络访问检查”">​</a></h3><ul><li>步骤目标：确认可以访问GitHub</li><li>执行位置：本机浏览器</li><li>检查方法：访问<a href="https://github.com/alirezarezvani/claude-skills" target="_blank" rel="noreferrer">https://github.com/alirezarezvani/claude-skills</a></li><li>成功标志：可以正常访问项目页面</li><li>失败处理：请配置海外网络环境 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><h2 id="主路径-安装与使用" tabindex="-1">主路径：安装与使用 <a class="header-anchor" href="#主路径-安装与使用" aria-label="Permalink to “主路径：安装与使用”">​</a></h2><h3 id="步骤1-安装claude-code插件" tabindex="-1">步骤1：安装Claude Code插件 <a class="header-anchor" href="#步骤1-安装claude-code插件" aria-label="Permalink to “步骤1：安装Claude Code插件”">​</a></h3><ul><li>步骤目标：在Claude Code中安装插件</li><li>执行位置：Claude Code终端</li><li>完整命令：<code>/plugin marketplace add alirezarezvani/claude-skills</code></li><li>成功标志：插件安装成功</li><li>失败处理：检查Claude Code版本和网络连接</li></ul><h3 id="步骤2-安装技能包" tabindex="-1">步骤2：安装技能包 <a class="header-anchor" href="#步骤2-安装技能包" aria-label="Permalink to “步骤2：安装技能包”">​</a></h3><ul><li>步骤目标：安装需要的技能包</li><li>执行位置：Claude Code终端</li><li>完整命令：<code>/plugin install marketing-</code>（根据需要选择技能）</li><li>成功标志：技能包安装成功</li><li>失败处理：查看可用的技能包列表</li></ul><h3 id="步骤3-使用技能" tabindex="-1">步骤3：使用技能 <a class="header-anchor" href="#步骤3-使用技能" aria-label="Permalink to “步骤3：使用技能”">​</a></h3><ul><li>步骤目标：开始使用已安装的技能</li><li>执行位置：Claude Code</li><li>使用方法：在对话中直接使用相应技能</li><li>成功标志：Claude能够使用专业技能完成任务</li><li>失败处理：确认技能已正确安装</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><h3 id="_1-测试hr技能" tabindex="-1">1. 测试HR技能 <a class="header-anchor" href="#_1-测试hr技能" aria-label="Permalink to “1. 测试HR技能”">​</a></h3><ul><li>测试方法：尝试使用HR相关技能，如KPI设计</li><li>预期返回：Claude能够使用专业技能完成任务</li></ul><h3 id="_2-查看可用技能" tabindex="-1">2. 查看可用技能 <a class="header-anchor" href="#_2-查看可用技能" aria-label="Permalink to “2. 查看可用技能”">​</a></h3><ul><li>测试方法：查看已安装的技能列表</li><li>预期返回：显示所有已安装的技能</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><h3 id="现象1-插件安装失败" tabindex="-1">现象1：插件安装失败 <a class="header-anchor" href="#现象1-插件安装失败" aria-label="Permalink to “现象1：插件安装失败”">​</a></h3><ul><li>可能原因：网络问题或Claude Code版本不兼容</li><li>解决步骤： <ol><li>检查网络连接</li><li>配置海外网络环境 <a href="/网络环境.html">海外网络环境配置 →</a></li><li>更新Claude Code到最新版本</li><li>重新尝试安装</li></ol></li></ul><h3 id="现象2-技能无法使用" tabindex="-1">现象2：技能无法使用 <a class="header-anchor" href="#现象2-技能无法使用" aria-label="Permalink to “现象2：技能无法使用”">​</a></h3><ul><li>可能原因：技能未正确安装或Claude Code配置问题</li><li>解决步骤： <ol><li>确认技能已正确安装</li><li>重启Claude Code</li><li>重新安装技能</li></ol></li></ul><h3 id="现象3-claude-code无法访问" tabindex="-1">现象3：Claude Code无法访问 <a class="header-anchor" href="#现象3-claude-code无法访问" aria-label="Permalink to “现象3：Claude Code无法访问”">​</a></h3><ul><li>可能原因：网络问题或权限问题</li><li>解决步骤： <ol><li>检查网络连接</li><li>确认有使用Claude Code的权限</li><li>尝试重新登录Claude Code</li></ol></li></ul><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><h3 id="使用openskills" tabindex="-1">使用OpenSkills <a class="header-anchor" href="#使用openskills" aria-label="Permalink to “使用OpenSkills”">​</a></h3><ul><li>适用场景：非Claude Code的第三方IDE或编程工具</li><li>参考项目：OpenSkills开源项目</li><li>步骤： <ol><li>查看OpenSkills文档</li><li>按照文档配置使用</li></ol></li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>基于公开可验证信息整理，完整教程请参考项目GitHub仓库的README文档。</p><p>更多详细文档请参考：</p><ul><li>GitHub仓库：<a href="https://github.com/alirezarezvani/claude-skills" target="_blank" rel="noreferrer">https://github.com/alirezarezvani/claude-skills</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',50)]))}const C=a(d,[["render",h]]);export{b as __pageData,C as default};
